package com.kalyani.car_rental_backend.driver.controller;import com.kalyani.car_rental_backend.driver.dto.DriverProfileRequest;import com.kalyani.car_rental_backend.driver.entity.DriverProfile;import com.kalyani.car_rental_backend.driver.repository.DriverProfileRepository;import com.kalyani.car_rental_backend.exception.ResourceNotFoundException;import com.kalyani.car_rental_backend.response.ApiResponse;import com.kalyani.car_rental_backend.user.entity.Role;import com.kalyani.car_rental_backend.user.repository.UserRepository;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController@RequestMapping("/driver")public class DriverController{private final DriverProfileRepository repo;private final UserRepository users;public DriverController(DriverProfileRepository r,UserRepository u){repo=r;users=u;}@GetMapping("/profile")public ResponseEntity<ApiResponse<Map<String,Object>>>profile(Authentication a){return ResponseEntity.ok(ApiResponse.success(out(find(a.getName())),"Driver profile loaded"));}@PostMapping("/profile")public ResponseEntity<ApiResponse<Map<String,Object>>>save(@Valid@RequestBody DriverProfileRequest r,Authentication a){var u=users.findByEmailIgnoreCase(a.getName()).orElseThrow(()->new ResourceNotFoundException("User not found"));if(u.getRole()!=Role.DRIVER)throw new IllegalArgumentException("Only DRIVER role can create driver profile");var p=repo.findByUserEmailIgnoreCase(a.getName()).orElseGet(()->{var x=new DriverProfile();x.setUser(u);return x;});p.setLicenseNumber(r.licenseNumber);p.setAadhaarLast4(r.aadhaarLast4);p.setVehicleNumber(r.vehicleNumber);p.setVehicleModel(r.vehicleModel);return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(out(repo.save(p)),"Driver profile submitted for verification"));}@PatchMapping("/availability")public ResponseEntity<ApiResponse<Map<String,Object>>>availability(@RequestParam boolean online,Authentication a){var p=find(a.getName());if(!"APPROVED".equals(p.getVerificationStatus())&&online)throw new IllegalArgumentException("Driver verification must be approved before going online");p.setOnline(online);return ResponseEntity.ok(ApiResponse.success(out(repo.save(p)),online?"You are online":"You are offline"));}@PatchMapping("/location")public ResponseEntity<ApiResponse<Map<String,Object>>>location(@RequestParam Double latitude,@RequestParam Double longitude,Authentication a){var p=find(a.getName());p.setCurrentLatitude(latitude);p.setCurrentLongitude(longitude);return ResponseEntity.ok(ApiResponse.success(out(repo.save(p)),"Location updated"));}private DriverProfile find(String e){return repo.findByUserEmailIgnoreCase(e).orElseThrow(()->new ResourceNotFoundException("Driver profile not found"));}private Map<String,Object>out(DriverProfile p){Map<String,Object>m=new LinkedHashMap<>();m.put("id",p.getId());m.put("name",p.getUser().getFullName());m.put("email",p.getUser().getEmail());m.put("verificationStatus",p.getVerificationStatus());m.put("online",p.isOnline());m.put("licenseNumber",p.getLicenseNumber());m.put("vehicleNumber",p.getVehicleNumber());m.put("vehicleModel",p.getVehicleModel());m.put("latitude",p.getCurrentLatitude());m.put("longitude",p.getCurrentLongitude());m.put("walletBalance",p.getWalletBalance());m.put("totalEarnings",p.getTotalEarnings());m.put("averageRating",p.getAverageRating());m.put("completedTrips",p.getCompletedTrips());return m;}}
